http.createServer((req, res) => {
  const requestId = String(Date.now());

  RequestContext.Provider({ requestId }, () => {
    console.log('sync log:', useContext(RequestContext)); // \u2705 \u6709\u503C

    setTimeout(() => {
      // \u274C \u8FD9\u91CC\u5DF2\u7ECF\u4E0D\u5728\u539F\u6765\u7684\u8C03\u7528\u6808\u91CC\u4E86
      console.log('async log:', useContext(RequestContext));
    }, 10);
  });
});
